"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["35120"],{24434(i){i.exports=JSON.parse('{"tag":{"label":"medtech","permalink":"/sysanalyst-kb.github.io/docs/tags/medtech","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":8,"items":[{"id":"specialization/medtech-path","title":"MedTech \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043A\u0430\u0440\u044C\u0435\u0440\u043D\u044B\u0439 \u043F\u0443\u0442\u044C \u0432 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0435 \u0438 \u0444\u0430\u0440\u043C\u0435","description":"MedTech-\u0430\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u043C\u0438 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u043C\u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0430\u043C\u0438 \u0436\u0451\u0441\u0442\u043A\u0430\u044F \u0440\u0435\u0433\u0443\u043B\u044F\u0446\u0438\u044F (323-\u0424\u0417, 152-\u0424\u0417, \u043E\u0431\u043E\u0440\u043E\u0442 \u043B\u0435\u043A\u0430\u0440\u0441\u0442\u0432), \u0441\u043B\u043E\u0436\u043D\u044B\u0435 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 (HL7 FHIR, DICOM), \u0432\u044B\u0441\u043E\u043A\u0438\u0435 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438 \u041F\u0414 \u0438 \u0440\u0430\u0431\u043E\u0442\u0430 \u0441 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u043E \u0432\u0430\u0436\u043D\u044B\u043C\u0438 \u0434\u0430\u043D\u043D\u044B\u043C\u0438 \u043F\u0430\u0446\u0438\u0435\u043D\u0442\u043E\u0432. \u0420\u044B\u043D\u043E\u043A MedTech \u0432 \u0420\u0424 \u2014 150+ \u043C\u043B\u0440\u0434 \u0440\u0443\u0431/\u0433\u043E\u0434, \u0431\u043E\u043B\u0435\u0435 10 000 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0445 \u043E\u0440\u0433\u0430\u043D\u0438\u0437\u0430\u0446\u0438\u0439 \u043D\u0443\u0436\u0434\u0430\u044E\u0442\u0441\u044F \u0432 \u0446\u0438\u0444\u0440\u043E\u0432\u0438\u0437\u0430\u0446\u0438\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-path"},{"id":"specialization/medtech-pacs","title":"PACS / DICOM \u2014 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0435 \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F","description":"PACS (Picture Archiving and Communication System) \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0434\u043B\u044F \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438 \u043F\u0440\u043E\u0441\u043C\u043E\u0442\u0440\u0430 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0445 \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0439 (\u0440\u0435\u043D\u0442\u0433\u0435\u043D, \u041A\u0422, \u041C\u0420\u0422, \u043C\u0430\u043C\u043C\u043E\u0433\u0440\u0430\u0444\u0438\u044F). DICOM \u2014 \u0441\u0442\u0430\u043D\u0434\u0430\u0440\u0442 \u0434\u043B\u044F \u043F\u0435\u0440\u0435\u0434\u0430\u0447\u0438 \u0438 \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F \u0438\u0437\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0439. \u0422\u0438\u043F\u043E\u0432\u043E\u0435 \u0445\u0440\u0430\u043D\u0438\u043B\u0438\u0449\u0435 \u043E\u0431\u043B\u0430\u0441\u0442\u043D\u043E\u0439 \u0431\u043E\u043B\u044C\u043D\u0438\u0446\u044B \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044F PACS \u0441 \u041C\u0418\u0421 (HL7), RIS (\u0440\u0430\u0434\u0438\u043E\u043B\u043E\u0433\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u0418\u0421), \u043C\u043E\u0434\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044F\u043C\u0438 (\u0430\u043F\u043F\u0430\u0440\u0430\u0442\u044B \u041A\u0422/\u041C\u0420\u0422), \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 5+ \u043B\u0435\u0442, DICOM-\u0442\u0435\u0433\u0438 (\u043C\u0435\u0442\u0430\u0434\u0430\u043D\u043D\u044B\u0435 \u0441\u043D\u0438\u043C\u043A\u0430).","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-pacs"},{"id":"specialization/medtech-lis","title":"\u041B\u0418\u0421 \u2014 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u044B\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u041B\u0418\u0421 (\u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u0430\u044F \u0418\u0421) \u0443\u043F\u0440\u0430\u0432\u043B\u044F\u0435\u0442 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u043E\u043C \u0430\u043D\u0430\u043B\u0438\u0437\u0430 \u0431\u0438\u043E\u043C\u0430\u0442\u0435\u0440\u0438\u0430\u043B\u043E\u0432 \u0448\u0442\u0440\u0438\u0445\u043A\u043E\u0434\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u0435 \u043F\u0440\u043E\u0431\u0438\u0440\u043E\u043A, \u0430\u0432\u0442\u043E\u0432\u0435\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F (70%+ \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u0432 \u0431\u0435\u0437 \u0443\u0447\u0430\u0441\u0442\u0438\u044F \u043B\u0430\u0431\u043E\u0440\u0430\u043D\u0442\u0430), \u0440\u0435\u0444\u0435\u0440\u0435\u043D\u0441\u043D\u044B\u0435 \u0438\u043D\u0442\u0435\u0440\u0432\u0430\u043B\u044B \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044F \u0441 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u043D\u044B\u043C\u0438 \u0430\u043D\u0430\u043B\u0438\u0437\u0430\u0442\u043E\u0440\u0430\u043C\u0438. \u0412 \u0442\u0438\u043F\u043E\u0432\u043E\u0439 \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u0438\u0438 \u2014 10 000+ \u043F\u0440\u043E\u0431/\u0434\u0435\u043D\u044C, \u0434\u043E 500 \u0432\u0438\u0434\u043E\u0432 \u0430\u043D\u0430\u043B\u0438\u0437\u043E\u0432.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-lis"},{"id":"specialization/medtech-mis","title":"\u041C\u0418\u0421 \u2014 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0435 \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B","description":"\u041C\u0418\u0421 (\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0430\u044F \u0438\u043D\u0444\u043E\u0440\u043C\u0430\u0446\u0438\u043E\u043D\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430) \u2014 \u043E\u0441\u043D\u043E\u0432\u043D\u0430\u044F \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0431\u043E\u043B\u044C\u043D\u0438\u0446\u044B \u0438\u043B\u0438 \u043F\u043E\u043B\u0438\u043A\u043B\u0438\u043D\u0438\u043A\u0438. \u041E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u042D\u041C\u041A, \u0440\u0430\u0441\u043F\u0438\u0441\u0430\u043D\u0438\u0435, \u043B\u0430\u0431\u043E\u0440\u0430\u0442\u043E\u0440\u0438\u044E, \u0440\u0430\u0434\u0438\u043E\u043B\u043E\u0433\u0438\u044E, \u0430\u043F\u0442\u0435\u043A\u0443, \u043E\u0442\u0447\u0451\u0442\u043D\u043E\u0441\u0442\u044C \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u0415\u0413\u0418\u0421\u0417. \u041A\u043B\u044E\u0447\u0435\u0432\u043E\u0439 \u0432\u044B\u0437\u043E\u0432: \u0441\u043B\u043E\u0436\u043D\u043E\u0441\u0442\u044C \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0439 (10+ \u043F\u043E\u0434\u0441\u0438\u0441\u0442\u0435\u043C) \u0438 compliance (323-\u0424\u0417, 152-\u0424\u0417). \u041A\u0440\u0443\u043F\u043D\u0435\u0439\u0448\u0430\u044F \u041C\u0418\u0421 \u0420\u0424 \u2014 \u0415\u041C\u0418\u0410\u0421 \u041C\u043E\u0441\u043A\u0432\u044B \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u0435\u0442 100M+ \u0437\u0430\u043F\u0438\u0441\u0435\u0439/\u0433\u043E\u0434.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-mis"},{"id":"specialization/medtech-regulations","title":"\u0420\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u0438\u043A\u0430 \u0432 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0435 (323-\u0424\u0417, 152-\u0424\u0417, \u043E\u0431\u043E\u0440\u043E\u0442 \u043B\u0435\u043A\u0430\u0440\u0441\u0442\u0432)","description":"\u041C\u0435\u0434\u0438\u0446\u0438\u043D\u0430 \u2014 \u043E\u0434\u043D\u0430 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0440\u0435\u0433\u0443\u043B\u0438\u0440\u0443\u0435\u043C\u044B\u0445 \u043E\u0442\u0440\u0430\u0441\u043B\u0435\u0439. \u0422\u0440\u0438 \u0441\u0442\u043E\u043B\u043F\u0430: 323-\u0424\u0417 (\u043E\u0445\u0440\u0430\u043D\u0430 \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u044F, \u042D\u041C\u041A, \u0442\u0435\u043B\u0435\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0430), 152-\u0424\u0417 (\u041F\u0414 \u043E\u0441\u043E\u0431\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438), \u043F\u043E\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u0435 \u2116 1275 (\u0415\u0413\u0418\u0421\u0417). \u0412\u0441\u0435 \u0434\u0430\u043D\u043D\u044B\u0435 \u043E \u0437\u0434\u043E\u0440\u043E\u0432\u044C\u0435 \u2014 \u041F\u0414 \u043E\u0441\u043E\u0431\u043E\u0439 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u0438 (\u0443\u0441\u0438\u043B\u0435\u043D\u043D\u0430\u044F \u0437\u0430\u0449\u0438\u0442\u0430 \u0423\u0417-1). \u041B\u044E\u0431\u0430\u044F \u041C\u0418\u0421 \u0434\u043E\u043B\u0436\u043D\u0430 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u043E\u0432\u0430\u0442\u044C \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F\u043C \u043A \u043E\u0431\u0440\u0430\u0431\u043E\u0442\u043A\u0435 \u041F\u0414 \u0438, \u0435\u0441\u043B\u0438 \u0432\u043B\u0438\u044F\u0435\u0442 \u043D\u0430 \u0432\u0440\u0430\u0447\u0435\u0431\u043D\u044B\u0435 \u0440\u0435\u0448\u0435\u043D\u0438\u044F, \u0440\u0435\u0433\u0438\u0441\u0442\u0440\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043A\u0430\u043A \u043C\u0435\u0434\u0438\u0437\u0434\u0435\u043B\u0438\u0435 (\u043A\u043B\u0430\u0441\u0441\u044B \u0440\u0438\u0441\u043A\u0430 2a, 2b, 3). \u0428\u0442\u0440\u0430\u0444\u044B \u0437\u0430 \u043D\u0430\u0440\u0443\u0448\u0435\u043D\u0438\u044F \u2014 \u0434\u043E 300 \u0442\u044B\u0441. \u0440\u0443\u0431. \u043F\u043E \u041A\u043E\u0410\u041F, \u0443\u0433\u043E\u043B\u043E\u0432\u043D\u0430\u044F \u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u2014 \u0437\u0430 \u0440\u0430\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u0438\u0435 \u041F\u0414 (\u0441\u0442. 137 \u0423\u041A \u0420\u0424).","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-regulations"},{"id":"specialization/medtech-telemedicine","title":"\u0422\u0435\u043B\u0435\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0430 \u0438 \u0434\u0438\u0441\u0442\u0430\u043D\u0446\u0438\u043E\u043D\u043D\u044B\u0435 \u043A\u043E\u043D\u0441\u0443\u043B\u044C\u0442\u0430\u0446\u0438\u0438","description":"\u0422\u0435\u043B\u0435\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0430 \u2014 \u0443\u0434\u0430\u043B\u0451\u043D\u043D\u043E\u0435 \u0432\u0437\u0430\u0438\u043C\u043E\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435 \u0432\u0440\u0430\u0447\u0430 \u0438 \u043F\u0430\u0446\u0438\u0435\u043D\u0442\u0430 \u0447\u0435\u0440\u0435\u0437 \u0432\u0438\u0434\u0435\u043E/\u0447\u0430\u0442. \u0421 2017 \u0433\u043E\u0434\u0430 \u0440\u0430\u0437\u0440\u0435\u0448\u0435\u043D\u0430 \u0432 \u0420\u0424 (323-\u0424\u0417, \u043F\u0440\u0438\u043A\u0430\u0437 \u2116 797\u043D). \u0421 2020 \u0433\u043E\u0434\u0430 \u043E\u0431\u044A\u0451\u043C \u0442\u0435\u043B\u0435\u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0445 \u043A\u043E\u043D\u0441\u0443\u043B\u044C\u0442\u0430\u0446\u0438\u0439 \u0432 \u0420\u0424 \u0432\u044B\u0440\u043E\u0441 \u0432 5 \u0440\u0430\u0437. \u0412\u043A\u043B\u044E\u0447\u0430\u0435\u0442 ONDOC, \u0421\u0431\u0435\u0440\u0417\u0434\u043E\u0440\u043E\u0432\u044C\u0435 (8M+ \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439), \u042F\u043D\u0434\u0435\u043A\u0441.\u0417\u0434\u043E\u0440\u043E\u0432\u044C\u0435, Doctor.Ru. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0446\u0435\u043D\u0430\u0440\u0438\u0438 \u043F\u0440\u0438\u0451\u043C\u0430, \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0441 \u041C\u0418\u0421 \u0438 \u042D\u041C\u041A, \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0432\u0438\u0434\u0435\u043E \u0438 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u0438.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-telemedicine"},{"id":"specialization/medtech-pharma","title":"\u0424\u0430\u0440\u043C\u0430 \u2014 \u0443\u0447\u0451\u0442 \u043B\u0435\u043A\u0430\u0440\u0441\u0442\u0432 \u0438 \u043C\u0430\u0440\u043A\u0438\u0440\u043E\u0432\u043A\u0430 (\u0427\u0435\u0441\u0442\u043D\u044B\u0439 \u0417\u041D\u0410\u041A)","description":"\u0424\u0430\u0440\u043C\u0430\u0446\u0435\u0432\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0439 \u0443\u0447\u0451\u0442 \u2014 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044C \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u043B\u0435\u043A\u0430\u0440\u0441\u0442\u0432 \u0432 \u0431\u043E\u043B\u044C\u043D\u0438\u0446\u0435: \u0437\u0430\u043A\u0443\u043F\u043A\u0430, \u043F\u0440\u0438\u0445\u043E\u0434, \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435, \u043E\u0442\u043F\u0443\u0441\u043A \u043F\u0430\u0446\u0438\u0435\u043D\u0442\u0430\u043C. \u0421 2020 \u0433\u043E\u0434\u0430 \u043E\u0431\u044F\u0437\u0430\u0442\u0435\u043B\u044C\u043D\u0430 \u043C\u0430\u0440\u043A\u0438\u0440\u043E\u0432\u043A\u0430 \u043F\u0440\u0435\u043F\u0430\u0440\u0430\u0442\u043E\u0432 \u0447\u0435\u0440\u0435\u0437 \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \xab\u0427\u0435\u0441\u0442\u043D\u044B\u0439 \u0417\u041D\u0410\u041A\xbb (\u0426\u0420\u041F\u0422). \u041A\u0430\u0436\u0434\u0430\u044F \u0443\u043F\u0430\u043A\u043E\u0432\u043A\u0430 \u2014 \u0443\u043D\u0438\u043A\u0430\u043B\u044C\u043D\u044B\u0439 DataMatrix-\u043A\u043E\u0434. \u041A 2025 \u0433\u043E\u0434\u0443 \u043C\u0430\u0440\u043A\u0438\u0440\u043E\u0432\u043A\u0430 \u043E\u0445\u0432\u0430\u0442\u044B\u0432\u0430\u0435\u0442 100% \u043B\u0435\u043A\u0430\u0440\u0441\u0442\u0432 \u0432 \u0420\u0424. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u044E \u0430\u043F\u0442\u0435\u0447\u043D\u043E\u0433\u043E \u0441\u043A\u043B\u0430\u0434\u0430 \u0441 \u041C\u0418\u0421 \u0438 \u043C\u0430\u0440\u043A\u0438\u0440\u043E\u0432\u043A\u0443 \u043D\u0430 \u0443\u0440\u043E\u0432\u043D\u0435 \u0435\u0434\u0438\u043D\u0438\u0446\u044B \u0442\u043E\u0432\u0430\u0440\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-pharma"},{"id":"specialization/medtech-emk","title":"\u042D\u041C\u041A \u2014 \u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u044B\u0435 \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0438\u0435 \u043A\u0430\u0440\u0442\u044B","description":"\u042D\u041C\u041A (\u044D\u043B\u0435\u043A\u0442\u0440\u043E\u043D\u043D\u0430\u044F \u043C\u0435\u0434\u0438\u0446\u0438\u043D\u0441\u043A\u0430\u044F \u043A\u0430\u0440\u0442\u0430) \u2014 \u044F\u0434\u0440\u043E \u043B\u044E\u0431\u043E\u0439 \u041C\u0418\u0421. \u0421\u043E\u0434\u0435\u0440\u0436\u0438\u0442 \u043A\u0430\u0436\u0434\u0430\u044F \u0437\u0430\u043F\u0438\u0441\u044C \u043F\u043E\u0434\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0423\u041A\u042D\u041F \u0432\u0440\u0430\u0447\u0430. \u0412 \u0420\u0424 \u0431\u043E\u043B\u0435\u0435 500M \u042D\u041C\u041A \u0432 \u0415\u0413\u0418\u0421\u0417 (\u0434\u0430\u043D\u043D\u044B\u0435 2024). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0443 \u042D\u041C\u041A, \u043F\u0440\u0430\u0432\u0430 \u0434\u043E\u0441\u0442\u0443\u043F\u0430 \u0438 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0439 \u0446\u0438\u043A\u043B \u0437\u0430\u043F\u0438\u0441\u0435\u0439.","permalink":"/sysanalyst-kb.github.io/docs/specialization/medtech-emk"}],"unlisted":false}}')}}]);